import {
  rectangle, rounded_rectangle, polygon,
  union, render,
} from '../../src/index.js';

// --- Single column: base + shaft + capital ---
function column(cx) {
  const base    = rounded_rectangle([0.085, 0.04], 0.005, [cx, -0.28]);
  const shaft   = rectangle([0.055, 0.48], [cx, 0.0]);
  const capital = rounded_rectangle([0.090, 0.045], 0.006, [cx, 0.27]);
  return union(base, shaft, capital);
}

// --- A row of 5 columns, equally spaced ---
const cols = union(
  column(-0.50), column(-0.25), column(0.00), column(0.25), column(0.50)
);

// Lintel (entablature) spanning the whole row, sitting on the capitals
const lintel = rectangle([1.25, 0.06], [0, 0.34]);

// Stylized triangular pediment above lintel
const pediment = polygon([
  [-0.60, 0.37],
  [ 0.00, 0.50],
  [ 0.60, 0.37],
]);

// Plinth / floor strip
const floor = rectangle([1.40, 0.05], [0, -0.34]);

// Background sky
const sky = rectangle([1.60, 1.20], [0, 0.0]);

const layers = [
  { sdf: sky,      color: [205, 215, 225] },
  { sdf: floor,    color: [180, 170, 150] },
  { sdf: cols,     color: [225, 215, 200] },
  { sdf: lintel,   color: [205, 195, 175] },
  { sdf: pediment, color: [215, 205, 185] },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [200, 215, 230], bottom: [220, 215, 200] },
});
```

**Composition notes**: 5 columns evenly spaced from x=-0.5 to x=0.5 (spacing 0.25). Each column has base+shaft+capital. Lintel sits on top spanning whole row. Triangular pediment crowns the colonnade. Classical sandy-cream stone palette.
